insert into mp_rs (mp_code, member_name, gender, party, state_ut, date_of_birth, place_of_birth, age, father_name, mother_name, marital_status, date_of_marriage, spouse_name, sons, daughters, educational_qualification, profession, profession1, profession2, profession3, previous_membership, email, mobile, mobile2, local_telephone, permanent_telephone, local_address, permanent_address, other_permanent_address, current_term, total_terms, status, notification_date, expiration_date, freedom_fighter, books_published, social_cultural, countries_visited, sports_clubs, other_information, brief_bio_data, positions_held, term_history) values ('2527', 'Shri Masthan Rao Yadav Beedha', 'Male', 'Telugu Desam Party', 'Andhra Pradesh', '02/07/1958', 'Iskapalli, SPS Nellore District, Andhra Pradesh', '67', 'Shri Ramanaiah', 'Shrimati Bujjamma', 'Married', '20 August 1987', 'Shrimati Beeda Venkata Manjula', 'One', 'one', 'B.Com., C.A. Educated at Sri Venkateswara University, Nellore and Institute of Chartered Accountants of India, Madras, Tamil Nadu', 'Industrialist and Businessman', NULL, NULL, NULL, NULL, 'bmr.yadav@sansad.nic.in', '9884032943', '8074361637', '8074361637, 906300909', '0861-2325515,044-24511374', 'Flat no. B-6 (Tower- A2), Deendayal Upadhyaya Marg, New Delhi- 110001', 'No.2-37, Iskapalli Village, Allur Mandal, SPSR Nellore District, Andhra Pradesh. 524003', NULL, '2024-2028', '2', 'Sitting', '13/12/2024', '21/06/2028', 'No', NULL, 'Dedicated social worker and visionary leader; founded the BMR Trust with the mission of uplifting communities and addressing critical societal needs like health, education, empowerment of women, skill development, strengthening social welfare hostels, support to housing, supply of safe drinking water, sports, and entrepreneurship development trainings, etc. in the rural and urban areas, thereby serving a population of more than 8 lakhs; the BMR Group has provided employment to 6000 youths, paving the way for improving their standard of living', 'U.S.A., Kenya, Mexico, Mauritius and Japan', 'Encourages and supports sports and games in Andhra Pradesh and Tamil Nadu; Member, (i) Andhra Club, Chennai, (ii) Gandhi Nagar Club, Chennai, (iii) Cosmopolitan Club, Chennai, (iv) Nellore Club, Nellore and (v) Constitution Club, New Delhi', 'A versatile personality having interest and shouldering responsibilities in several spheres, such as business, politics, social service, spirituality and philanthropy, etc.; Chairman, BMR Group of industries; fondly known as ‘Father of Vannamei’ for introduction of Litopenaeus vennamei in India; a well-known name in the aqua community; with a modest beginning in sea food industries with shrimp farming at Iskapalli in 1991, started BMR Group, which has been working in all wings of aqua culture viz. Broodstock Multiplication Centre, hatcheries, farming, feed industry, processing plant and exports, etc.; expanded his group into 400 hectares farming, 12 hatcheries, shrimp process unit, a feed plant, broodstock multiplication centre, etc.; the group is one of the largest seed supplier, with 6.5 billion annual seed production; introduced Shrimp L-Vannamei exotic species in India; as a result India is now the second largest exporter of shrimp in the world market with an annual export value of Rs. 30420 crore; the Group has been awarded ‘Best Hatchery in India’ award, by MPEDA, in 2015; awarded, (i) Honorary Doctorate Degree by the International University of Contemporary Studies, Washington DC, U.S.A. in recognition of his vision, innovative thinking and unrelenting efforts, 1998, (ii)‘Indian of the year 2017 - Aqua Culture’ by Shri Suresh Prabhu, the then Hon’ble Union Minister of Railways, (iii) Lifetime Achievement award, by India International Aquaculture Expo, Chennai, 2022 and (iv) ‘Best Hatchery Award’, 2024, by Government of Andhra Pradesh; instrumental in formulating policies that had greatly supported the aqua farmers and industry; the suggestions impacted the formulation of pro-aqua policies like subsidized power, grants-in-aid to new industries, subsidized supply of fishing nets and boats to fishermen, subsidies for setting up of cold storages, reefer containers, etc.; President, Shrimp Feed Manufacturers Association(SFMA) since 2021', NULL, '• Member, Joint Committee on the Corporate Laws (Amendment) Bill, 2026 (May 2026 onwards)
• Member, Committee on Petitions (May 2026 onwards)
• Member, India – Morocco Parliamentary Friendship Group (Feb. 2026 onwards)
• Member, Committee on Industry (Sept. 2025 onwards)
• Member, Committee on Rural Development and Panchayati Raj (-)
• Member, Committee on Agriculture, Animal Husbandry and Food Processing (Aug. - Sept 2025)
• Elected to Rajya Sabha (second term) (Dec. 2024)
• Member, Committee on Welfare of Other Backward Classes (Aug. 2024 and Sept. 2025 onwards)
• Member, Committee on Members of Parliament Local Area Development Scheme (Jan. 2023 - Aug. 2024)
• Member, Joint Committee on the Jan Vishwas (Amendment of Provisions) BIll, 2022 (Dec. 2022 - March 2023)
• Member, Joint Committee on Offices of Profit (Dec. 2022 - June 2024)
• Member, Consultative Committee for the Ministry of Commerce and Industry
• Member, Committee on Agriculture, Animal Husbandry and Food Processing (Sept. 2022 - June 2024)
• Elected to Rajya Sabha (resigned w.e.f. 29 August 2024) (June 2022)
• Advisory Member, Andhra Pradesh Capital Region Development Authority (AP CRDA) (2014 - 2019)
• Chairman, Standing Committee on Labour, Factories, Employment and Training, Tourism and Information Technology, Andhra Pradesh Legislative Assembly
• Member, Committee on Welfare of Backward Classes, Andhra Pradesh Legislative Assembly
• Member, Andhra Pradesh Legislative Assembly (2009 -2014)', '• Term 1: 22/06/2022-21/06/2028 (Andhra Pradesh, Yuvajana Sramika Rythu Congress Party)
• Term 2: 13/12/2024-21/06/2028 (Andhra Pradesh, Telugu Desam Party)')
