insert into mp_rs (mp_code, member_name, gender, party, state_ut, date_of_birth, place_of_birth, age, father_name, mother_name, marital_status, date_of_marriage, spouse_name, sons, daughters, educational_qualification, profession, profession1, profession2, profession3, previous_membership, email, mobile, mobile2, local_telephone, permanent_telephone, local_address, permanent_address, other_permanent_address, current_term, total_terms, status, notification_date, expiration_date, freedom_fighter, books_published, social_cultural, countries_visited, sports_clubs, other_information, brief_bio_data, positions_held, term_history) values ('2528', 'Shri Ryaga Krishnaiah', 'Male', 'Bharatiya Janata Party', 'Andhra Pradesh', '13/09/1954', 'Village Ralla Gudupally, Mominpet, Vikarabad, Distt. Rangareddy (Andhra Pradesh)', '71', 'Shri Adivappa', 'Shrimati Ramulamma', 'Married', NULL, 'Shrimati R. Shabari', NULL, NULL, 'B. Com., LL.B., M.A., LL.M., M.Phil. Educated at P.G College of Law and Osmania University, Hyderabad, Telangana', NULL, NULL, NULL, NULL, NULL, 'ryaga.krishnaiah@sansad.nic.in', '9000009164', NULL, '23238020', NULL, 'Flat no. A-7 (Tower- A2), Deendayal Upadhyaya Marg, New Delhi- 110002', 'D. No. 1-9-669/43/A, Vidyanagar, Musheerabad,Hyderabad, Telangana State', NULL, '2024-2028', '2', 'Sitting', '13/12/2024', '21/06/2028', 'No', 'Wrote more than 300 articles in various leading dailies', 'Mass leader, outstanding orator; his efforts have lead to the upliftment of the Backward Classes in Andhra Pradesh; has led three pro-reservation movements in the state that lead to the implementation of recommendations of the Muralidhar Rao Commission Report, (1986) and the Mandal Commission Report, (1990); Editor, BC Garjana, a monthly magazine with a circulation of 40,000 copies, which covers various issues pertaining to social evils; was Editor, "Voice of weaker section", a leading Telugu monthly magazine, 1982-1992 with a circulation of 30,000 copies; organized public meetings for the welfare of the backward class people; helped in introducing ‘Full Fees Reimbursement Schemes’, in 2008, benefitting 30 lakh college and university students; helped in providing ‘full mess charges scheme and scholarships’ to the backward class University students, 1976; made efforts to increase the number of SC/ST/BC hostels from 600 to 6000 benefitting around 8 lakh students at school and college levels; strived for the sanctioning of 1500 SC/ST/BC/Minority welfare residential schools; fought against corruption in the recruitment process of Andhra Pradesh Public Service Commission; Awards, (i) National Ambedkar Award, 2003, by National SC Welfare Organization, (ii) National Mahatma Jyothi Rao Pule Award, 2011', NULL, NULL, 'Was the Chief Minister candidate for TDP and BJP alliance during the 2014 elections, in Telangana, 2014; Founder President, BC Student Association (founded in 1978); President, (i) National Backward Classes Welfare Association, (ii) 140 Unions of OBC employers of Central and State Government Departments, (iii) Social Welfare Hostel (SC, ST and OBC) Students'' Union, 1976-2004; In-Charge, RSS, 1970-79; Former President, (i) Andhra Pradesh Social Welfare Hostel Students Union from 1976- 2004, (ii) Andhra Pradesh State Unemployees Struggle Committee, (iii) Andhra Pradesh Class IV Employees Central Association, (iv) Andhra Pradesh State Sama Sangram Parishad, a pro-reservation organization, Pro-Mandal agitation A.P. State Reservation Protection Committee; Chairman, (i) Andhra Pradesh Social Welfare Hostel Students Joint Action Committee, 1978, (ii) State Joint Action Committee formed with the state organization of PDSU, RSU, AISF, SFI, DSO, 1979, 1980-84, (iii) Joint Committee for Pro-reservation Organisation, 2006, (iv) State Joint Action Committee formed against levying capitation fees and donations in private colleges, 1992; was State Leader, ABVP, 1972-78; was President, Students Union, Osmania University and P.G College of Law, 1980-82; organised around 12 thousand public meetings, dharnas, rallies, party meetings, etc. 1973-2022; addressed more than 6 thousand public meetings in all parts of the state; made efforts to achieve 34 reservation for the BCs in Zilla parishads, mandal parishads, gram panchayats, municipalities, local body elections, 1986; under his leadership the BC Welfare Association has organized agitations in the state and introduced all the existing schemes meant for Backward Classes and Scheduled Castes students such as hostels, scholarships, exemption from tuition fees, reservations, self employment, student loans, residential schools, etc.; associated with the National Backward Classes Welfare Association; was Chief Guest, at several meetings of students'' unions of Junior/Degree /University colleges; organized meetings, seminars, public meetings against caste system and untouchability; fought against the practice of capitation fees, donations in private engineering colleges; excelled in academics and had been recipient of several Gold medals at University level; during school/ college/ University days, was awarded first prize more than 400 times for elocution competition, essay writing, quiz competitions; received opportunities to pursue a career in the State/Central Government, instead dedicated his life for the upliftment of the weaker sections of the society; committed with a vision to give education to all belonging to the oppressed sections of the society; as Chief Guest, addressed hundreds of meetings of the Jana Sangh in Andhra Pradesh, 1975-78', NULL, '• Member, India - Mauritius Parliamentary Friendship Group (Feb. 2026 onwards)
• Member, Committee on Consumer Affairs, Food and Public Distribution (Jan. 2025 onwards)
• Elected to Rajya Sabha (second term) (Dec.2024)
• Member, Consultative Committee for the Ministry of Social Justice and Empowerment
• Member, Committee on Finance (Sept. 2022 - June 2024)
• Elected to Rajya Sabha (resigned w.e.f. 23 September 2024) (June 2022)
• Member, Andhra Pradesh Legislative Assembly (2014-2018)', '• Term 1: 22/06/2022-21/06/2028 (Andhra Pradesh, Yuvajana Sramika Rythu Congress Party)
• Term 2: 13/12/2024-21/06/2028 (Andhra Pradesh, Bharatiya Janata Party)')
