insert into mp_rs (mp_code, member_name, gender, party, state_ut, date_of_birth, place_of_birth, age, father_name, mother_name, marital_status, date_of_marriage, spouse_name, sons, daughters, educational_qualification, profession, profession1, profession2, profession3, previous_membership, email, mobile, mobile2, local_telephone, permanent_telephone, local_address, permanent_address, other_permanent_address, current_term, total_terms, status, notification_date, expiration_date, freedom_fighter, books_published, social_cultural, countries_visited, sports_clubs, other_information, brief_bio_data, positions_held, term_history) values ('2081', 'Shri Parimal Nathwani', 'Male', 'Yuvajana Sramika Rythu Congress Party', 'Andhra Pradesh', '01/02/1956', 'Mumbai (Maharashtra)', '70', 'Shri Dhirajlal Nathwani', 'Shrimati Pushpa Nathwani', 'Married', '25 May 1984', 'Shrimati Varsha Nathwani', 'One', NULL, 'Professional Doctorate in Management Educated at National Institute of Management, Ahmedabad, Gujarat', 'Industrialist, Senior Corporate Leader/ Executive', NULL, NULL, NULL, NULL, 'parimal.nathwani@sansad.nic.in', '9868181299', '9825211111', '011-46584432 011-24648713,23794010, 23012879', '079 35555500,8511109499', '15 Lodhi Estate, New Delhi 110003', 'Vraj, Near Vishwa Umiyadham Umiya Dham Road, Jaspur Village, Ahmedabad - 382721', NULL, '2020-2026', '3', 'Sitting', '22/06/2020', '21/06/2026', 'No', 'In Hindi, Jharkhand: Meri Karmabhoom; In English, (i) Gir Lion: Pride of Gujarat and (ii) Adorable and Admirable Parimal Nathwani (both in association with Times of India), (iii) ‘Call of the Gir’ and (iv) The One and Only… Dhirubhai Ambani (published in Gujarati, Hindi and English).', 'Founder Chairman and Trustee, Reliance Rural Development Trust (an NGO), which has carried out approximately 6246 works in 5558 villages across 25 districts of Gujarat for rural development; Chairman, Indian Institute of Public Health, Gandhi Nagar;Trustee, Board of Governor''s Social Welfare Fund, Gujarat;Chancellor, Shree Bruhad Gujarat Sanskrut Parishad; Member, (i) Nathdwara Temple Board, (ii) Gujarat Ayurved University Development Board and (iii) Board of Governors of Pandit Deendayal Energy University; Founder Director, GEET Foundation, an NGO for promoting environmental and ecological tourism in Gir', 'Russia, Switzerland, South Korea, Japan, Uganda, Kenya, as a Member of the delegation of the Government of Gujarat led by the Hon''ble Chief Minister; Austria, France, U.S.A., U.A.E., Thailand, China and Europe', 'President, Gujarat State Football Association; formerVice-President, Gujarat Cricket Association; Executive Member, Lions Club of Jamnagar; Member, Rotary Club of Jamnagar; Lifetime Member, Constitution Club of India; over the last 35 years gathered extensive insights and knowledge about Gir lions, Gir fauna and flora as well as the Maldharis residing in and around Gir in Gujarat', 'As Vice-President of Gujarat Cricket Association (GCA), successfully planned, monitored, supervised and executed construction of the world’s largest cricket stadium at Ahmedabad, the ‘Narendra Modi Stadium’; very passionate about wildlife, especially GirLions; had been working for conservation and protection of the Gir Lions, the last remaining Asiatic Lions in the world; made a documentary titled ‘Parimal Nathwani : Gir Aur Lion Ko Samarpit Ek Shakhsiyat’; also, published a 12-episode video documentary on Asiatic Lion of Gir called ‘The Pride Kingdom’; Member, Advisory Committee, Gir Sanctuary and National Park, Government of Gujarat', NULL, '• Member, India - South Korea Parliamentary Friendship Group (Feb. 2026 onwards)
• Member, Committee on Rules (Nov. 2022 - Dec. 2024)
• Member, District Level Committee of Andhra Pradesh for the District of Chittoor for the implementation of Prime Minister''s 15 Point Programme for the Welfare of Minorities (February 2021 onwards)
• Member, Joint Hindi Salahakar Samiti (Advisory Committee) for the Department of Space and Department of Atomic Energy (May 2021 onwards)
